import { Fragment, type ReactNode, createElement, useCallback, useEffect, useSyncExternalStore } from "react";
import { THEME_IDS, type ThemeId } from "@t3tools/contracts";
import { getThemeById } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";
const OLD_STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID: ThemeId = "t3-dark";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeId | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function isValidThemeId(value: string | null): value is ThemeId {
  return value !== null && (THEME_IDS as readonly string[]).includes(value);
}

// Migrate from old light/dark/system key on first load
function migrateOldTheme(): void {
  if (localStorage.getItem(STORAGE_KEY) !== null) return;
  const old = localStorage.getItem(OLD_STORAGE_KEY);
  if (old === null) return;
  localStorage.setItem(STORAGE_KEY, old === "light" ? "t3-light" : "t3-dark");
}

function getStored(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (isValidThemeId(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = getThemeById(themeId);
  const isDark = theme.colorScheme === "dark";

  document.documentElement.setAttribute("data-theme", themeId);
  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.style.colorScheme = theme.colorScheme;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
migrateOldTheme();
applyTheme(getStored());

function getSnapshot(): ThemeId {
  const themeId = getStored();
  if (lastSnapshot === themeId) return lastSnapshot;
  lastSnapshot = themeId;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  const theme = getThemeById(themeId);
  return { themeId, theme, setTheme } as const;
}

export function ThemeProvider({ children }: { children: ReactNode }) {
  useTheme();
  return createElement(Fragment, null, children);
}

