import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Theme preference">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(theme.id)}
          >
            {/* Swatch strip: background / sidebar / accent */}
            <div className="flex h-8 w-full overflow-hidden rounded-md" aria-hidden="true">
              <div className="flex-1" style={{ background: theme.colors.background }} />
              <div className="w-6 shrink-0" style={{ background: theme.colors.sidebar }} />
              <div className="w-4 shrink-0" style={{ background: theme.colors.accent }} />
            </div>

            {/* Label row */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-xs font-medium">{theme.label}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  On
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

